def _canonicalize_value(value: Any) -> Any:
    """Recursively canonicalize a value for stable fingerprinting.

    Dict keys are sorted, tuples are converted to lists, and strings are stripped of
    leading/trailing whitespace. Numeric and boolean types are left untouched.
    """
    if isinstance(value, dict):
        return {k: _canonicalize_value(v) for k, v in sorted(value.items())}
    if isinstance(value, (list, tuple)):
        return [_canonicalize_value(v) for v in value]
    if isinstance(value, str):
        return value.strip()
    return value


def _compute_fingerprint(name: str, args: dict[str, Any]) -> tuple[str, str]:
    """Compute a stable (fingerprint, id) pair for a tool call's name and args."""
    canonical = {"name": name, "args": _canonicalize_value(args)}
    serialized = json.dumps(canonical, sort_keys=True, separators=(",", ":"))
    fingerprint = hashlib.sha256(serialized.encode("utf-8")).hexdigest()
    return fingerprint, fingerprint[:8]


def _split_code_and_comment(line: str) -> tuple[str, str | None]:
    """Split a line into (code, comment) at the first unquoted `#`."""
    in_string = False
    string_char = ""
    escape = False
    for i, ch in enumerate(line):
        if escape:
            escape = False
            continue
        if ch == "\\":
            escape = True
            continue
        if in_string:
            if ch == string_char:
                in_string = False
            continue
        if ch in ("'", '"'):
            in_string = True
            string_char = ch
            continue
        if ch == "#":
            return line[:i], line[i + 1 :].strip()
    return line, None


def _parse_calls_and_comments(text: str) -> tuple[list[dict[str, Any]], list[str | None]]:
    """Parse raw text containing JSON tool call objects interleaved with Python comments.

    Comments that precede, are inline with, or immediately follow a JSON object are all
    associated with that object. Returns the parsed dicts alongside the combined comment
    string for each (or None if no comment was found).
    """
    blocks = []
    floating_comments: list[str] = []
    current: dict[str, Any] | None = None

    for raw_line in text.split("\n"):
        code_part, comment_part = _split_code_and_comment(raw_line)
        if comment_part:
            if current is not None:
                current["comments"].append(comment_part)
            else:
                floating_comments.append(comment_part)

        stripped_code = code_part.strip()
        if not stripped_code:
            continue

        for ch in stripped_code:
            if ch == "{":
                if current is not None and current["depth"] == 0 and current["json_lines"]:
                    blocks.append(current)
                    current = None
                if current is None:
                    current = {"json_lines": [], "comments": floating_comments, "depth": 0}
                    floating_comments = []
                current["depth"] += 1
            elif ch == "}":
                if current is not None:
                    current["depth"] -= 1

        if current is not None:
            current["json_lines"].append(code_part)

    if current is not None:
        blocks.append(current)

    parsed_dicts = []
    comments_list = []
    for block in blocks:
        parsed_dicts.append(json.loads("\n".join(block["json_lines"])))
        comments_list.append("\n".join(block["comments"]) if block["comments"] else None)

    return parsed_dicts, comments_list


class ToolCalls(Type):
    class ToolCall(BaseModel):
        name: str
        args: dict[str, Any]

        # Metadata fields: never passed to the underlying `Tool` and excluded from the
        # fingerprint. Purely for logging, debugging, or UI display.
        note: str | None = None
        comment: str | None = None
        annotation: str | None = None
        tags: list[str] | None = None
        priority: str | int | None = None
        meta: dict[str, Any] | None = None

        # Read-only, computed once at creation time from `name` and `args` alone.
        fingerprint: str = ""
        id: str = ""

        def __init__(self, **data):
            data.pop("fingerprint", None)
            data.pop("id", None)
            super().__init__(**data)
            fingerprint, short_id = _compute_fingerprint(self.name, self.args)
            object.__setattr__(self, "fingerprint", fingerprint)
            object.__setattr__(self, "id", short_id)

        def has_metadata(self) -> bool:
            return any(getattr(self, field) is not None for field in _METADATA_FIELDS)

    tool_calls: list[ToolCall]

    @classmethod
    def from_dict_list(
        cls, tool_calls_dicts: list[dict[str, Any]], comments: list[str | None] | None = None
    ) -> "ToolCalls":
        """Convert a list of dictionaries to a ToolCalls instance.

        Args:
            tool_calls_dicts: A list of dictionaries, where each dictionary should have 'name' and 'args' keys,
                along with any optional metadata fields (`note`, `comment`, `annotation`, `tags`, `priority`, `meta`).
            comments: Optional list of Python-style comments, one per entry in `tool_calls_dicts`. When provided,
                these take precedence over any explicit `comment` field on the corresponding dictionary.

        Returns:
            A ToolCalls instance.

        Example:

            ```python
            tool_calls_dict = [
                {"name": "search", "args": {"query": "hello"}},
                {"name": "translate", "args": {"text": "world"}}
            ]
            tool_calls = ToolCalls.from_dict_list(tool_calls_dict)
            ```
        """
        tool_calls = []
        for i, item in enumerate(tool_calls_dicts):
            item = dict(item)
            if comments is not None and i < len(comments) and comments[i]:
                item["comment"] = comments[i]
            tool_calls.append(cls.ToolCall(**item))
        return cls(tool_calls=tool_calls)

    @classmethod
    def from_string(cls, text: str) -> "ToolCalls":
        """Parse a raw string containing JSON tool call objects and Python-style `#` comments.

        Comments found near a call (before, inline, or immediately after) are combined and
        attached to that call's `comment` field, taking precedence over any explicit `comment`
        field present in the JSON itself.
        """
        tool_calls_dicts, comments = _parse_calls_and_comments(text)
        return cls.from_dict_list(tool_calls_dicts, comments=comments)

    @classmethod
    def description(cls) -> str:
        return (
            "Tool calls information, including the name of the tools and the arguments to be passed to it. "
            "Arguments must be provided in JSON format."
        )

    def format(self) -> list[dict[str, Any]] | dict[str, Any]:
        # The tool_call field is compatible with OpenAI's tool calls schema.
        tool_calls = [
            {
                "type": "function",
                "function": {
                    "name": tool_call.name,
                    "arguments": tool_call.args,
                },
            }
            for tool_call in self.tool_calls
        ]
        if any(tool_call.has_metadata() for tool_call in self.tool_calls):
            return [{"type": "tool_calls", "tool_calls": tool_calls}]
        return {"tool_calls": tool_calls}

    def format_with_metadata(self) -> list[dict[str, Any]]:
        """Like `format()`, but includes metadata fields for debugging/logging purposes."""
        tool_calls = []
        for tool_call in self.tool_calls:
            call_dict = {
                "type": "function",
                "function": {
                    "name": tool_call.name,
                    "arguments": tool_call.args,
                },
            }
            for field in _METADATA_FIELDS:
                value = getattr(tool_call, field)
                if value is not None:
                    call_dict[field] = value
            tool_calls.append(call_dict)
        return [{"type": "tool_calls", "tool_calls": tool_calls}]"}

